{"code": "import json

# Read NYSE non-ETF stocks
file_path = locals()['var_functions.query_db:62']
with open(file_path, 'r') as f:
    nyse_stocks = json.load(f)

# Create mapping of symbol to company name
symbol_to_company = {}
for stock in nyse_stocks:
    symbol = stock['Symbol']
    desc = stock['Company Description']

    if ' specializes in' in desc:
        name = desc.split(' specializes in')[0]
    elif ' is ' in desc:
        name = desc.split(' is ')[0]
    elif ' offers ' in desc:
        name = desc.split(' offers ')[0]
    elif ' provides ' in desc:
        name = desc.split(' provides ')[0]
    elif ' excels in' in desc:
        name = desc.split(' excels in')[0]
    elif ' is a ' in desc:
        name = desc.split(' is a ')[0]
    elif ' is an ' in desc:
        name = desc.split(' is an ')[0]
    elif ' operates as' in desc:
        name = desc.split(' operates as')[0]
    else:
        name = desc

    symbol_to_company[symbol] = name.strip()

# Read available tables in stocktrade_database
file_path2 = locals()['var_functions.list_db:10']
with open(file_path2, 'r') as f:
    all_tables = json.load(f)

# Find NYSE symbols that have data tables
available_nyse_symbols = [sym for sym in symbol_to_company.keys() if sym in all_tables]

print('__RESULT__:')
print(json.dumps({
    'available_nyse_stocks': len(available_nyse_symbols),
    'total_nyse_stocks': len(symbol_to_company),
    'sample_available': available_nyse_symbols[:20]
}))"}
